import React, { useState, useEffect } from 'react';
import './ManualInput.css';

const ManualInput = ({ items, setItems, language }) => {
  const [newItem, setNewItem] = useState({ name: '', category: '', material: '' });
  const [editingId, setEditingId] = useState(null);
  const [isListening, setIsListening] = useState(false);
  const [recognition, setRecognition] = useState(null);
  const [currentField, setCurrentField] = useState('name');

  useEffect(() => {
    // Initialize speech recognition
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      const recognitionInstance = new SpeechRecognition();
      
      recognitionInstance.continuous = false;
      recognitionInstance.interimResults = false;
      recognitionInstance.maxAlternatives = 1;
      
      recognitionInstance.onstart = () => {
        console.log('Voice recognition started');
        setIsListening(true);
      };
      
      recognitionInstance.onresult = (event) => {
        console.log('Voice recognition result:', event);
        if (event.results && event.results[0] && event.results[0][0]) {
          const transcript = event.results[0][0].transcript.trim();
          console.log('Transcript:', transcript, 'Field:', currentField);
          setNewItem(prev => ({
            ...prev,
            [currentField]: transcript
          }));
        }
      };
      
      recognitionInstance.onerror = (event) => {
        console.error('Speech recognition error:', event.error);
        setIsListening(false);
        // Show user-friendly error message
        if (event.error === 'no-speech') {
          alert('No speech detected. Please try again.');
        } else if (event.error === 'network') {
          alert('Network error. Please check your connection.');
        } else {
          alert(`Voice recognition error: ${event.error}`);
        }
      };
      
      recognitionInstance.onend = () => {
        console.log('Voice recognition ended');
        setIsListening(false);
      };
      
      setRecognition(recognitionInstance);
    }
  }, [currentField]); // Remove language dependency to avoid recreation

  // Update language when it changes
  useEffect(() => {
    if (recognition) {
      recognition.lang = language === 'ta' ? 'ta-IN' : 'en-US';
    }
  }, [language, recognition]);

  const startVoiceInput = (field) => {
    if (recognition && !isListening) {
      try {
        setCurrentField(field);
        recognition.lang = language === 'ta' ? 'ta-IN' : 'en-US';
        
        // Stop any ongoing recognition first
        recognition.stop();
        
        // Small delay to ensure previous recognition is stopped
        setTimeout(() => {
          recognition.start();
        }, 100);
      } catch (error) {
        console.error('Error starting voice recognition:', error);
        setIsListening(false);
        alert('Could not start voice recognition. Please try again.');
      }
    }
  };

  const stopVoiceInput = () => {
    if (recognition && isListening) {
      try {
        recognition.stop();
      } catch (error) {
        console.error('Error stopping voice recognition:', error);
      }
      setIsListening(false);
    }
  };

  const translations = {
    en: {
      title: 'Manual Input',
      itemName: 'Item Name',
      category: 'Category',
      material: 'Material',
      add: 'Add Item',
      edit: 'Edit',
      delete: 'Delete',
      save: 'Save',
      cancel: 'Cancel',
      voiceInput: 'Voice Input',
      listening: 'Listening...',
      stopListening: 'Stop',
      voiceNotSupported: 'Voice input not supported',
      placeholder: {
        name: 'e.g., Chair, Lights, Flowers',
        category: 'e.g., Furniture, Lighting, Decor',
        material: 'e.g., Wood, Metal, Plastic'
      }
    },
    ta: {
      title: 'கைமுறை உள்ளீடு',
      itemName: 'பொருளின் பெயர்',
      category: 'வகை',
      material: 'பொருள்',
      add: 'பொருள் சேர்க்க',
      edit: 'திருத்து',
      delete: 'நீக்கு',
      save: 'சேமி',
      cancel: 'ரத்து',
      voiceInput: 'குரல் உள்ளீடு',
      listening: 'கேட்கிறது...',
      stopListening: 'நிறுத்து',
      voiceNotSupported: 'குரல் உள்ளீடு ஆதரிக்கப்படவில்லை',
      placeholder: {
        name: 'உதா., நாற்காலி, விளக்குகள், பூக்கள்',
        category: 'உதா., மரச்சாமான்கள், விளக்கு, அலங்காரம்',
        material: 'உதா., மரம், உலோகம், பிளாஸ்டிக்'
      }
    }
  };

  const t = translations[language];

  const handleAddItem = () => {
    if (newItem.name.trim()) {
      const item = {
        id: Date.now(),
        name: newItem.name.trim(),
        category: newItem.category.trim() || 'Other',
        material: newItem.material.trim() || 'Unknown'
      };
      setItems([...items, item]);
      setNewItem({ name: '', category: '', material: '' });
    }
  };

  const handleEditItem = (id) => {
    const item = items.find(item => item.id === id);
    setNewItem({ name: item.name, category: item.category, material: item.material });
    setEditingId(id);
  };

  const handleSaveEdit = () => {
    if (newItem.name.trim()) {
      setItems(items.map(item => 
        item.id === editingId 
          ? { ...item, name: newItem.name.trim(), category: newItem.category.trim() || 'Other', material: newItem.material.trim() || 'Unknown' }
          : item
      ));
      setNewItem({ name: '', category: '', material: '' });
      setEditingId(null);
    }
  };

  const handleCancelEdit = () => {
    setNewItem({ name: '', category: '', material: '' });
    setEditingId(null);
  };

  const handleDeleteItem = (id) => {
    setItems(items.filter(item => item.id !== id));
  };

  const handleKeyPress = (event) => {
    if (event.key === 'Enter') {
      if (editingId) {
        handleSaveEdit();
      } else {
        handleAddItem();
      }
    }
  };

  return (
    <div className="manual-input">
      <h3>{t.title}</h3>
      
      <div className="input-form">
        <div className="input-group">
          <input
            type="text"
            placeholder={t.placeholder.name}
            value={newItem.name}
            onChange={(e) => setNewItem({ ...newItem, name: e.target.value })}
            onKeyPress={handleKeyPress}
            className="input-field"
          />
          <button 
            className={`voice-input-btn ${isListening && currentField === 'name' ? 'listening' : ''}`}
            onClick={() => isListening && currentField === 'name' ? stopVoiceInput() : startVoiceInput('name')}
            disabled={!recognition}
            title={recognition ? t.voiceInput : t.voiceNotSupported}
          >
            {isListening && currentField === 'name' ? '⏹️' : '🎤'}
          </button>
        </div>
        
        <div className="input-group">
          <input
            type="text"
            placeholder={t.placeholder.category}
            value={newItem.category}
            onChange={(e) => setNewItem({ ...newItem, category: e.target.value })}
            onKeyPress={handleKeyPress}
            className="input-field"
          />
          <button 
            className={`voice-input-btn ${isListening && currentField === 'category' ? 'listening' : ''}`}
            onClick={() => isListening && currentField === 'category' ? stopVoiceInput() : startVoiceInput('category')}
            disabled={!recognition}
            title={recognition ? t.voiceInput : t.voiceNotSupported}
          >
            {isListening && currentField === 'category' ? '⏹️' : '🎤'}
          </button>
        </div>
        
        <div className="input-group">
          <input
            type="text"
            placeholder={t.placeholder.material}
            value={newItem.material}
            onChange={(e) => setNewItem({ ...newItem, material: e.target.value })}
            onKeyPress={handleKeyPress}
            className="input-field"
          />
          <button 
            className={`voice-input-btn ${isListening && currentField === 'material' ? 'listening' : ''}`}
            onClick={() => isListening && currentField === 'material' ? stopVoiceInput() : startVoiceInput('material')}
            disabled={!recognition}
            title={recognition ? t.voiceInput : t.voiceNotSupported}
          >
            {isListening && currentField === 'material' ? '⏹️' : '🎤'}
          </button>
        </div>
        
        {isListening && (
          <div className="listening-indicator">
            <div className="pulse-animation"></div>
            <span>{t.listening}</span>
          </div>
        )}
        
        <div className="button-group">
          {editingId ? (
            <>
              <button onClick={handleSaveEdit} className="save-btn">
                {t.save}
              </button>
              <button onClick={handleCancelEdit} className="cancel-btn">
                {t.cancel}
              </button>
            </>
          ) : (
            <button onClick={handleAddItem} className="add-btn">
              {t.add}
            </button>
          )}
        </div>
      </div>

      <div className="items-list">
        {items.map(item => (
          <div key={item.id} className="item-card">
            <div className="item-info">
              <h4>{item.name}</h4>
              <p className="item-category">{item.category}</p>
              <p className="item-material">{item.material}</p>
            </div>
            <div className="item-actions">
              <button 
                onClick={() => handleEditItem(item.id)} 
                className="edit-btn"
                disabled={editingId !== null}
              >
                {t.edit}
              </button>
              <button 
                onClick={() => handleDeleteItem(item.id)} 
                className="delete-btn"
              >
                {t.delete}
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ManualInput;
